package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnPostSubmitProxy struct {
	automation.UnimplementedOnPostSubmitServer
	client automation.OnPostSubmitClient
}

func init() {
	proxyutil.Register(&automation.OnPostSubmit_ServiceDesc, NewOnPostSubmitProxy)
}
func NewOnPostSubmitProxy(cc grpc.ClientConnInterface) automation.OnPostSubmitServer {
	return &OnPostSubmitProxy{client: automation.NewOnPostSubmitClient(cc)}
}
func (p *OnPostSubmitProxy) OnPostSubmit(ctx context.Context, in *events.PostSubmit) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.PostSubmit, automation.HandlerResult](p.client.OnPostSubmit)(ctx, in)
}
